1	import {
2	  readItems,
3	  createItem,
4	  updateItem,
5	  deleteItem,
6	  readUsers,
7	  readComments,
8	  createComment,
9	} from '@directus/sdk'
10	import { directus } from '@/lib/directus'
11	import type { ChecklistItem, Subtask, ProductAssignee, Comment, DirectusUser } from '@/lib/types'
12	
13	// eslint-disable-next-line @typescript-eslint/no-explicit-any
14	const USER_FIELDS = ['id', 'first_name', 'last_name', 'email', 'avatar'] as any
15	
16	// ---- Checklist ----
17	export async function listChecklist(productId: string) {
18	  return directus.request(
19	    readItems('checklist_item', { filter: { product: { _eq: productId } }, sort: ['sort', 'id'], limit: -1 }),
20	  ) as Promise<ChecklistItem[]>
21	}
22	export async function addChecklist(productId: string, label: string) {
23	  return directus.request(createItem('checklist_item', { product: productId, label, done: false })) as Promise<ChecklistItem>
24	}
25	export async function setChecklistDone(id: string, done: boolean) {
26	  return directus.request(updateItem('checklist_item', id, { done }))
27	}
28	export async function removeChecklist(id: string) {
29	  return directus.request(deleteItem('checklist_item', id))
30	}
31	
32	// ---- Subtasks ----
33	export async function listSubtasks(productId: string) {
34	  return directus.request(
35	    readItems('subtask', {
36	      filter: { product: { _eq: productId } },
37	      fields: ['id', 'title', 'done', 'due_date', { assignee: USER_FIELDS }] as any,
38	      sort: ['sort', 'id'],
39	      limit: -1,
40	    }),
41	  ) as unknown as Promise<Subtask[]>
42	}
43	export async function addSubtask(productId: string, title: string) {
44	  return directus.request(createItem('subtask', { product: productId, title, done: false })) as Promise<Subtask>
45	}
46	export async function setSubtaskDone(id: string, done: boolean) {
47	  return directus.request(updateItem('subtask', id, { done }))
48	}
49	
50	// ---- Assignees (M2M via product_assignee) ----
51	export async function listAssignees(productId: string) {
52	  return directus.request(
53	    readItems('product_assignee', {
54	      filter: { product: { _eq: productId } },
55	      fields: ['id', { directus_user: USER_FIELDS }] as any,
56	      limit: -1,
57	    }),
58	  ) as unknown as Promise<ProductAssignee[]>
59	}
60	export async function addAssignee(productId: string, userId: string) {
61	  return directus.request(createItem('product_assignee', { product: productId, directus_user: userId })) as Promise<ProductAssignee>
62	}
63	export async function removeAssignee(rowId: string) {
64	  return directus.request(deleteItem('product_assignee', rowId))
65	}
66	export async function listUsers() {
67	  return directus.request(
68	    readUsers({ fields: USER_FIELDS, filter: { status: { _eq: 'active' } }, sort: ['first_name'], limit: -1 }),
69	  ) as unknown as Promise<DirectusUser[]>
70	}
71	
72	// ---- Comments (native directus_comments) ----
73	export async function listComments(productId: string) {
74	  return directus.request(
75	    readComments({
76	      filter: { collection: { _eq: 'product' }, item: { _eq: productId } },
77	      fields: ['id', 'comment', 'date_created', { user_created: USER_FIELDS }] as any,
78	      sort: ['date_created'],
79	      limit: -1,
80	    }),
81	  ) as unknown as Promise<Comment[]>
82	}
83	export async function addComment(productId: string, text: string) {
84	  return directus.request(createComment({ collection: 'product', item: productId, comment: text }))
85	}
86	
87	export function userName(u: DirectusUser | string | null | undefined) {
88	  if (!u || typeof u === 'string') return 'Unknown'
89	  return [u.first_name, u.last_name].filter(Boolean).join(' ') || u.email || 'Unknown'
90	}
91	export function userInitials(u: DirectusUser | string | null | undefined) {
92	  return userName(u).split(' ').filter(Boolean).slice(0, 2).map((s) => s[0]?.toUpperCase()).join('') || '?'
93	}
