1	import type { MockTask } from '@/lib/mockData'
2	import { CATEGORY_COLORS, CATEGORY_ICONS, LICENSOR_META, STAGE_COLORS, PRIORITY_COLORS, PEOPLE } from '@/lib/mockData'
3	import type { ColorBy } from '@/lib/appState'
4	import { CheckSquare, MessageSquare, Paperclip, Flag } from 'lucide-react'
5	
6	function cardBg(task: MockTask, colorBy: ColorBy): string {
7	  switch (colorBy) {
8	    case 'category': return CATEGORY_COLORS[task.category]?.bg ?? '#fff'
9	    case 'licensor': {
10	      const meta = LICENSOR_META[task.licensor]
11	      if (meta) {
12	        // derive a pastel tint from the first stop of the gradient
13	        const match = meta.gradient.match(/#[0-9A-Fa-f]{6}/)
14	        if (match) {
15	          const hex = match[0].slice(1)
16	          const r = parseInt(hex.slice(0, 2), 16)
17	          const g = parseInt(hex.slice(2, 4), 16)
18	          const b = parseInt(hex.slice(4, 6), 16)
19	          return `rgba(${r},${g},${b},0.12)`
20	        }
21	      }
22	      return '#F6F8FC'
23	    }
24	    case 'stage': return STAGE_COLORS[task.stage]?.bg ?? '#fff'
25	    case 'priority': {
26	      const map: Record<string, string> = {
27	        urgent: '#FBD9D9', high: '#FBE8D2', normal: '#DEEBFB', low: '#EEF1F6',
28	      }
29	      return map[task.priority] ?? '#fff'
30	    }
31	    default: return '#fff'
32	  }
33	}
34	
35	const PILL_STYLES: Record<string, { bg: string; color: string }> = {
36	  blocked:  { bg: '#F6CDBC', color: '#9E3B1C' },
37	  Feedback: { bg: '#C7E3FB', color: '#1C6BAA' },
38	  ASAP:     { bg: '#F4BBA4', color: '#8E3315' },
39	}
40	
41	export function PimTaskCard({
42	  task,
43	  colorBy = 'category',
44	  onOpen,
45	  dragging = false,
46	}: {
47	  task: MockTask
48	  colorBy?: ColorBy
49	  onOpen: (t: MockTask) => void
50	  dragging?: boolean
51	}) {
52	  const catColors = CATEGORY_COLORS[task.category]
53	  const licMeta = LICENSOR_META[task.licensor]
54	  const pill = task.pill ? PILL_STYLES[task.pill] : null
55	  const priorityColor = PRIORITY_COLORS[task.priority]
56	  const bg = cardBg(task, colorBy)
57	
58	  const assigneeObjects = task.assignees
59	    .map((id) => PEOPLE.find((p) => p.id === id))
60	    .filter(Boolean) as typeof PEOPLE
61	
62	  return (
63	    <div
64	      onClick={() => !dragging && onOpen(task)}
65	      className="cursor-pointer select-none overflow-hidden rounded-xl transition-all"
66	      style={{
67	        background: colorBy === 'none' ? '#fff' : bg,
68	        border: colorBy === 'none' ? '1px solid #EAEEF5' : `1px solid ${bg}`,
69	        opacity: dragging ? 0.4 : 1,
70	        boxShadow: '0 1px 3px rgba(20,40,80,0.06)',
71	        width: 296,
72	      }}
73	      onMouseEnter={e => {
74	        ;(e.currentTarget as HTMLElement).style.boxShadow = '0 10px 22px -10px rgba(20,40,80,0.28)'
75	        ;(e.currentTarget as HTMLElement).style.transform = 'translateY(-2px)'
76	      }}
77	      onMouseLeave={e => {
78	        ;(e.currentTarget as HTMLElement).style.boxShadow = '0 1px 3px rgba(20,40,80,0.06)'
79	        ;(e.currentTarget as HTMLElement).style.transform = 'translateY(0)'
80	      }}
81	    >
82	      {task.coverUrl && (
83	        <img
84	          src={task.coverUrl}
85	          alt=""
86	          loading="lazy"
87	          className="h-28 w-full object-cover"
88	        />
89	      )}
90	      <div className="p-[13px_14px]">
91	      {/* Title row: category tile + title */}
92	      <div className="flex items-start gap-2.5">
93	        <div
94	          className="flex size-[30px] shrink-0 items-center justify-center rounded-lg text-base"
95	          style={{ background: catColors?.bg ?? '#F6F8FC' }}
96	        >
97	          <span style={{ fontSize: 16 }}>{CATEGORY_ICONS[task.category] ?? '📦'}</span>
98	        </div>
99	        <p
100	          className="line-clamp-2 flex-1 font-semibold leading-[1.32]"
101	          style={{ fontSize: 13.5, color: '#1B2840', letterSpacing: '-0.01em' }}
102	        >
103	          {task.title}
104	        </p>
105	      </div>
106	
107	      {/* Tags row: licensor badge + optional status pill */}
108	      <div className="mt-2.5 flex items-center gap-1.5">
109	        {licMeta && (
110	          <div
111	            className="flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-bold text-white"
112	            style={{ background: licMeta.gradient, fontSize: 11 }}
113	          >
114	            <span>{licMeta.letter}</span>
115	            <span className="font-semibold opacity-90" style={{ fontSize: 10.5 }}>{task.licensor}</span>
116	          </div>
117	        )}
118	        {pill && (
119	          <span
120	            className="rounded-full px-2 py-0.5 text-[10.5px] font-bold"
121	            style={{ background: pill.bg, color: pill.color }}
122	          >
123	            {task.pill}
124	          </span>
125	        )}
126	      </div>
127	
128	      {/* Meta row */}
129	      <div className="mt-2.5 flex items-center justify-between">
130	        {/* Left: time + due */}
131	        <div className="flex items-center gap-2 text-[11.5px]" style={{ color: '#94A0B5' }}>
132	          {task.time && <span>{task.time}</span>}
133	          {task.due && (
134	            <>
135	              <span>·</span>
136	              <span style={{ color: task.dueOver ? '#D2502B' : '#94A0B5' }}>{task.due}</span>
137	            </>
138	          )}
139	          {task.priority !== 'normal' && (
140	            <Flag className="size-3 ml-0.5" style={{ color: priorityColor }} />
141	          )}
142	        </div>
143	
144	        {/* Right: checklist / comments / attachments + avatars */}
145	        <div className="flex items-center gap-2">
146	          {task.checklist.total > 0 && (
147	            <span className="flex items-center gap-0.5 text-[10.5px] font-medium" style={{ color: '#3FA85C' }}>
148	              <CheckSquare className="size-3" />
149	              {task.checklist.done}/{task.checklist.total}
150	            </span>
151	          )}
152	          {task.comments > 0 && (
153	            <span className="flex items-center gap-0.5 text-[10.5px] font-medium" style={{ color: '#2C8FE0' }}>
154	              <MessageSquare className="size-3" />
155	              {task.comments}
156	            </span>
157	          )}
158	          {task.attach > 0 && (
159	            <span className="flex items-center gap-0.5 text-[10.5px] font-medium" style={{ color: '#D29A2E' }}>
160	              <Paperclip className="size-3" />
161	              {task.attach}
162	            </span>
163	          )}
164	          {/* Assignee avatars */}
165	          <div className="flex">
166	            {assigneeObjects.slice(0, 3).map((p, i) => (
167	              <div
168	                key={p.id}
169	                className="flex size-[22px] shrink-0 items-center justify-center rounded-full border-2 border-white text-[8px] font-bold text-white"
170	                style={{
171	                  background: p.color,
172	                  marginLeft: i === 0 ? 0 : -6,
173	                  position: 'relative',
174	                  zIndex: 3 - i,
175	                }}
176	                title={p.name}
177	              >
178	                {p.initials}
179	              </div>
180	            ))}
181	          </div>
182	        </div>
183	      </div>
184	      </div> {/* end p-[13px_14px] */}
185	    </div>
186	  )
187	}
