1	import { useState } from 'react'
2	import { NOTES, type MockNote } from '@/lib/mockData'
3	import { Bold, Italic, Underline, List } from 'lucide-react'
4	
5	export function NotesPage() {
6	  const [selected, setSelected] = useState<MockNote>(NOTES[0])
7	
8	  return (
9	    <div className="flex h-full overflow-hidden">
10	      {/* Notes list */}
11	      <div
12	        className="flex w-[336px] shrink-0 flex-col overflow-y-auto"
13	        style={{ borderRight: '1px solid #EAEEF5' }}
14	      >
15	        {NOTES.map((note) => {
16	          const isActive = note.id === selected.id
17	          return (
18	            <div
19	              key={note.id}
20	              onClick={() => setSelected(note)}
21	              className="cursor-pointer px-4 py-3.5 transition-colors"
22	              style={{
23	                background: isActive ? '#E4F1FF' : 'transparent',
24	                borderBottom: '1px solid #EAEEF5',
25	              }}
26	              onMouseEnter={e => { if (!isActive) (e.currentTarget as HTMLElement).style.background = '#F6F8FC' }}
27	              onMouseLeave={e => { if (!isActive) (e.currentTarget as HTMLElement).style.background = 'transparent' }}
28	            >
29	              <p className="truncate text-[13.5px] font-semibold" style={{ color: '#1B2840' }}>
30	                {note.title}
31	              </p>
32	              <p className="mt-0.5 line-clamp-2 text-[12.5px] leading-relaxed" style={{ color: '#5A6883' }}>
33	                {note.preview}
34	              </p>
35	              <p className="mt-1.5 text-[11px]" style={{ color: '#94A0B5' }}>{note.date}</p>
36	            </div>
37	          )
38	        })}
39	      </div>
40	
41	      {/* Document editor */}
42	      <div className="flex flex-1 flex-col overflow-hidden">
43	        {/* Formatting toolbar */}
44	        <div
45	          className="flex shrink-0 items-center gap-1 px-6 py-3"
46	          style={{ borderBottom: '1px solid #EAEEF5' }}
47	        >
48	          <select
49	            className="h-8 rounded-lg border-0 bg-[#F6F8FC] px-2 text-[12.5px] font-medium outline-none"
50	            style={{ color: '#5A6883' }}
51	          >
52	            <option>Normal text</option>
53	            <option>Heading 1</option>
54	            <option>Heading 2</option>
55	          </select>
56	          <div
57	            className="mx-2"
58	            style={{ width: 1, height: 20, background: '#EAEEF5' }}
59	          />
60	          {[
61	            { Icon: Italic, label: 'Italic' },
62	            { Icon: Bold, label: 'Bold' },
63	            { Icon: Underline, label: 'Underline' },
64	            { Icon: List, label: 'List' },
65	          ].map(({ Icon, label }) => (
66	            <button
67	              key={label}
68	              title={label}
69	              className="flex items-center justify-center rounded-lg p-1.5 transition-colors hover:bg-[#F6F8FC]"
70	            >
71	              <Icon className="size-4" style={{ color: '#5A6883' }} />
72	            </button>
73	          ))}
74	        </div>
75	
76	        {/* Note body */}
77	        <div className="flex-1 overflow-y-auto px-10 py-8" style={{ maxWidth: 720, margin: '0 auto', width: '100%' }}>
78	          <NoteBody note={selected} />
79	        </div>
80	      </div>
81	    </div>
82	  )
83	}
84	
85	function NoteBody({ note }: { note: MockNote }) {
86	  const lines = note.body.split('\n')
87	
88	  return (
89	    <div>
90	      {lines.map((line, i) => {
91	        if (line.startsWith('# ')) {
92	          return (
93	            <h1 key={i} className="mb-4 font-extrabold" style={{ fontSize: 30, color: '#1B2840', letterSpacing: '-0.02em' }}>
94	              {line.slice(2)}
95	            </h1>
96	          )
97	        }
98	        if (line.startsWith('## ')) {
99	          return (
100	            <h2 key={i} className="mb-2 mt-6 font-bold" style={{ fontSize: 18, color: '#1B2840' }}>
101	              {line.slice(3)}
102	            </h2>
103	          )
104	        }
105	        if (line.startsWith('- ')) {
106	          return (
107	            <li key={i} className="ml-4 text-[14.5px] leading-[1.7]" style={{ color: '#5A6883' }}>
108	              {line.slice(2)}
109	            </li>
110	          )
111	        }
112	        if (line === '') {
113	          return <div key={i} className="h-2" />
114	        }
115	        return (
116	          <p key={i} className="text-[14.5px] leading-[1.7]" style={{ color: '#5A6883' }}>
117	            {line}
118	          </p>
119	        )
120	      })}
121	    </div>
122	  )
123	}
